       const json = JSON.stringify(payload)
       const proc = Bun.spawn(hookCmd(hookName), {
         cwd: directory,
-        stdin: new Blob([json + "\n"]),
-        stdout: "ignore",
-        stderr: "ignore",
+        stdin: new Blob([json + '\n']),
+        stdout: 'ignore',
+        stderr: 'ignore',
       })
       await proc.exited
     } catch {
       // Silently ignore — plugin failures must not crash OpenCode
     }
   }

