             const msg = messageStore.get(part.messageID)
-            if (msg?.role === "user" && part.type === "text" && !seenUserMessages.has(msg.id)) {
+            if (msg?.role === 'user' && part.type === 'text' && !seenUserMessages.has(msg.id)) {
               seenUserMessages.add(msg.id)
               const sessionID = msg.sessionID ?? currentSessionID
               if (sessionID) {
