           }

-          case "session.compacted": {
+          case 'session.compacted': {
             const sessionID = (event as any).properties?.sessionID
             if (!sessionID) break
-            await callHook("compaction", {
+            await callHook('compaction', {
               session_id: sessionID,
             })
             break
           }

-          case "session.deleted": {
+          case 'session.deleted': {
             const session = (event as any).properties?.info
             if (!session?.id) break
