import { getViteConfig } from 'astro/config'
import { defineConfig } from 'vitest/config'

export default defineConfig(
  getViteConfig({
    test: {
      environment: 'happy-dom',
      setupFiles: ['./tests/setup.ts'],
      include: ['tests/**/*.test.ts'],
    },
  }),
)

import { describe, expect, it } from 'vitest'
import type { RawAppointment } from '@/types'
import {
  formatDate,
  formatCurrency,
  formatDateCompact,
  formatDatespan,
  formatDatetime,
  formatDuration,
  formatTimespan,
} from '@/utils'

const toUtcIso = (year: number, month: number, day: number, hours = 0, minutes = 0) =>
  new Date(Date.UTC(year, month - 1, day, hours, minutes)).toISOString()

const appointment = (fields: Partial<RawAppointment>): RawAppointment => ({
  sort_index: 0,
  ...fields,
})

describe('formatDate', () => {
  const cases: Array<[Date, string]> = [
    [new Date(Date.UTC(2024, 0, 15)), '15. Januar 2024'],
    [new Date(Date.UTC(2024, 2, 9)), '9. März 2024'],
    [new Date(Date.UTC(2024, 11, 1)), '1. Dezember 2024'],
  ]
  for (const [input, expected] of cases) {
    it(`formats ${input.toISOString()} as ${expected}`, () => {
      expect(formatDate(input)).toBe(expected)
    })
  }
})

describe('formatDatetime', () => {
  const cases: Array<[string, string]> = [
    [toUtcIso(2024, 1, 15, 14, 30), 'Do, 15. Jan 2024, 14:30 Uhr'],
    [toUtcIso(2024, 3, 9, 9, 5), 'Di, 9. Apr 2024, 9:05 Uhr'],
    [toUtcIso(2024, 12, 31, 23, 59), 'Di, 31. Dez 2024, 23:59 Uhr'],
  ]
  for (const [input, expected] of cases) {
    it(`formats ${input} as ${expected}`, () => {
      expect(formatDatetime(input)).toBe(expected)
    })
  }
})

describe('formatDateCompact', () => {
  const cases: Array<[string, string]> = [
    [toUtcIso(2024, 1, 15, 14, 30), 'Do, 15. Jan, 14:30 Uhr'],
    [toUtcIso(2024, 3, 9, 9, 5), 'Di, 9. Apr, 9:05 Uhr'],
    [toUtcIso(2024, 12, 31, 23, 59), 'Di, 31. Dez, 23:59 Uhr'],
  ]
  for (const [input, expected] of cases) {
    it(`formats ${input} as ${expected}`, () => {
      expect(formatDateCompact(input)).toBe(expected)
    })
  }
})

describe('formatDatespan', () => {
  describe('date-only (start_date / end_date)', () => {
    it('single day renders just the start in long form', () => {
      const result = formatDatespan(appointment({ start_date: '2024-01-15', end_date: '2024-01-15' }))
      expect(result).toBe('Mo, 15. Jan 2024')
    })

    it('multi-day span renders both days joined with a dash', () => {
      const result = formatDatespan(appointment({ start_date: '2024-01-15', end_date: '2024-01-18' }))
      expect(result).toBe('Mo, 15. Jan 2024 - Do, 18. Jan 2024')
    })

    it('span across months and years', () => {
      const result = formatDatespan(appointment({ start_date: '2024-12-30', end_date: '2025-01-02' }))
      expect(result).toBe('Mo, 30. Dez 2024 - Do, 2. Jan 2025')
    })
  })

  describe('datetime-only (start_date_time / end_date_time)', () => {
    it('same-calendar-day collapse renders only the start (default locale, no de)', () => {
      const result = formatDatespan(
        appointment({
          start_date_time: toUtcIso(2024, 1, 15, 14, 30),
